const uint8_t* font_mega_alpha_for(char c) {
    const uint8_t uc = static_cast<uint8_t>(c);
    if (uc < static_cast<uint8_t>(kFontFirstChar) ||
        uc > static_cast<uint8_t>(kFontLastChar)) {
        return kFallbackMegaAlpha;
    }
    return kFontMegaAlpha[uc - static_cast<uint8_t>(kFontFirstChar)];
}
